proof:
-- We'll use the fact that $\log(n!) > n \log n - n + 1$ for $n > 1$.
have h_log : Real.log (n ! : ℝ) > n * Real.log n - n + 1 := by
  induction hn <;> norm_num [ Nat.factorial_succ ] at *;
  · linarith [ Real.log_lt_sub_one_of_pos zero_lt_two ( by norm_num ) ];
  · rw [ Real.log_mul ( by positivity ) ( by positivity ) ];
    -- We'll use the fact that $Real.log (m + 1) < Real.log m + \frac{1}{m}$ for $m \geq 2$.
    have h_log : ∀ m : ℕ, 2 ≤ m → Real.log (m + 1) < Real.log m + 1 / m := by
      intro m hm; rw [ Real.log_lt_iff_lt_exp, Real.exp_add, Real.exp_log ( by positivity ) ] <;> try positivity; ; ring_nf; (
      nlinarith [ Real.add_one_lt_exp ( by positivity : ( m : ℝ ) ⁻¹ ≠ 0 ), ( by norm_cast : ( 2 : ℝ ) ≤ m ), mul_inv_cancel₀ ( by positivity : ( m : ℝ ) ≠ 0 ) ]);
    nlinarith [ h_log _ ‹_›, one_div_mul_cancel ( by positivity : ( ( Nat.cast:ℕ →ℝ ) ‹_› ) ≠ 0 ) ];
-- Exponentiating both sides of the inequality $\log(n!) > n \log n - n + 1$, we get $n! > e^{n \log n - n + 1}$.
have h_exp : (n ! : ℝ) > Real.exp (n * Real.log n - n + 1) := by
  rwa [ gt_iff_lt, Real.lt_log_iff_exp_lt ( by positivity ) ] at h_log;
convert h_exp using 1 ; ring ; norm_num [ Real.exp_add, Real.exp_sub, Real.exp_nat_mul, Real.exp_log, show n > 0 by linarith ] ; ring;
norm_num [ mul_assoc, mul_comm, mul_left_comm, ← Real.exp_nat_mul, ← Real.exp_neg, ← Real.exp_add, e ]

